#define lowbit(x) ((x)&-(x))

int main(){

	int n,m,i,j;

	cin >> n >> m;

	for(i=1;i<(1<<n);++i){

		for(j=1;j<(1<<m);++j)

			putchar((lowbit(i)==lowbit(j))+'0');

		puts("");

	}

	return 0;

}
